module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output wire [15:0] result
);

    reg [17:0] SR;
    reg [8:0] neg_divisor;
    reg [3:0] cnt;
    reg start_cnt;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            SR <= 0;
            neg_divisor <= 0;
            cnt <= 0;
            start_cnt <= 0;
            res_valid <= 0;
        end
        else if (opn_valid && !res_valid) begin
            if (!start_cnt) begin
                if (sign) begin
                    if (dividend[7]) begin
                        SR <= {{16{1'b1}}, dividend};
                        neg_divisor <= {{8{1'b1}}, ~divisor + 1'b1};
                    end
                    else begin
                        SR <= {{16{1'b0}}, dividend};
                        neg_divisor <= {{8{1'b0}}, ~divisor + 1'b1};
                    end
                end
                else begin
                    if (divisor[7]) begin
                        SR <= {{16{1'b1}}, dividend};
                        neg_divisor <= {{8{1'b1}}, ~divisor + 1'b1};
                    end
                    else begin
                        SR <= {{16{1'b0}}, dividend};
                        neg_divisor <= {{8{1'b0}}, ~divisor + 1'b1};
                    end
                end
                start_cnt <= 1'b1;
                cnt <= 1'b1;
            end
            else begin
                if (cnt == 4'd7) begin
                    SR <= {SR[16:1]};
                    start_cnt <= 1'b0;
                    res_valid <= 1'b1;
                end
                else begin
                    SR <= {SR[16:1]} - {1'b0, neg_divisor};
                    cnt <= cnt + 1'b1;
                end
            end
        end
        else begin
            res_valid <= 1'b0;
        end
    end

    assign result = {SR[15:8], SR[7:0]};

endmodule
